import{_ as a,o as t,c as i,ae as l}from"./chunks/framework.DhtYoOpx.js";const s=JSON.parse('{"title":"Vue2 与 Vue3 Diff 算法区别（面试版）","description":"","frontmatter":{},"headers":[],"relativePath":"articles/vue/Vue2与Vue3Diff算法区别.md","filePath":"articles/vue/Vue2与Vue3Diff算法区别.md","lastUpdated":1776330050000}'),o={name:"articles/vue/Vue2与Vue3Diff算法区别.md"};function d(r,e,h,c,n,u){return t(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="vue2-与-vue3-diff-算法区别-面试版" tabindex="-1">Vue2 与 Vue3 Diff 算法区别（面试版） <a class="header-anchor" href="#vue2-与-vue3-diff-算法区别-面试版" aria-label="Permalink to &quot;Vue2 与 Vue3 Diff 算法区别（面试版）&quot;">​</a></h1><p>本文档适配 VitePress 渲染规范，聚焦 Vue2 与 Vue3 Diff 算法的核心差异，包含面试高频考点、算法解析、对比表格及标准回答，可直接复制到 VitePress 项目中使用，兼顾可读性与考点完整性。</p><h2 id="一、核心区别-一句话总结-面试开篇必答" tabindex="-1">一、核心区别（一句话总结，面试开篇必答） <a class="header-anchor" href="#一、核心区别-一句话总结-面试开篇必答" aria-label="Permalink to &quot;一、核心区别（一句话总结，面试开篇必答）&quot;">​</a></h2><ul><li><p><strong>Vue2</strong>：纯运行时双端对比，全量遍历虚拟 DOM，无编译期优化，靠启发式算法减少 DOM 操作。</p></li><li><p><strong>Vue3</strong>：编译期标记 + 运行时靶向更新 + 最长递增子序列（LIS），仅对比动态节点，实现最少 DOM 移动。</p></li></ul><h2 id="二、整体设计思路差异" tabindex="-1">二、整体设计思路差异 <a class="header-anchor" href="#二、整体设计思路差异" aria-label="Permalink to &quot;二、整体设计思路差异&quot;">​</a></h2><h3 id="_2-1-vue2-diff-设计思路" tabindex="-1">2.1 Vue2 Diff 设计思路 <a class="header-anchor" href="#_2-1-vue2-diff-设计思路" aria-label="Permalink to &quot;2\\.1 Vue2 Diff 设计思路&quot;">​</a></h3><ul><li><p>完全依赖 <strong>运行时</strong> 进行 Diff 对比，无任何编译期优化操作。</p></li><li><p>每次组件更新，都会 <strong>全量遍历整棵虚拟 DOM 树</strong>，即使是无动态绑定的静态节点，也会参与对比。</p></li><li><p>列表 Diff 核心采用 <strong>双端双指针启发式对比</strong>，尽量减少 DOM 移动。</p></li></ul><h3 id="_2-2-vue3-diff-设计思路" tabindex="-1">2.2 Vue3 Diff 设计思路 <a class="header-anchor" href="#_2-2-vue3-diff-设计思路" aria-label="Permalink to &quot;2\\.2 Vue3 Diff 设计思路&quot;">​</a></h3><ul><li><p>采用 <strong>编译时优化 + 运行时优化</strong> 结合的方式，大幅提升更新性能。</p></li><li><p>编译阶段：给虚拟 DOM 节点打上 <code>PatchFlag</code> 标记，区分静态节点与动态节点，明确动态节点的更新类型。</p></li><li><p>运行阶段：仅对带有 <code>PatchFlag</code> 的 <strong>动态节点</strong> 进行 Diff 对比，直接跳过静态节点。</p></li><li><p>列表 Diff 采用 <strong>前后预处理 + 最长递增子序列（LIS）</strong> 算法，确保 DOM 移动次数最少。</p></li></ul><h2 id="三、列表-diff-核心算法对比-面试重点" tabindex="-1">三、列表 Diff 核心算法对比（面试重点） <a class="header-anchor" href="#三、列表-diff-核心算法对比-面试重点" aria-label="Permalink to &quot;三、列表 Diff 核心算法对比（面试重点）&quot;">​</a></h2><h3 id="_3-1-vue2-双端对比算法" tabindex="-1">3.1 Vue2：双端对比算法 <a class="header-anchor" href="#_3-1-vue2-双端对比算法" aria-label="Permalink to &quot;3\\.1 Vue2：双端对比算法&quot;">​</a></h3><p>核心逻辑：通过四个指针控制对比范围，依次尝试匹配，减少 DOM 操作，属于启发式算法（非最优解）。</p><h4 id="核心指针" tabindex="-1">核心指针 <a class="header-anchor" href="#核心指针" aria-label="Permalink to &quot;核心指针&quot;">​</a></h4><ul><li><p><code>oldStartIndex</code>：旧列表起始索引</p></li><li><p><code>oldEndIndex</code>：旧列表结束索引</p></li><li><p><code>newStartIndex</code>：新列表起始索引</p></li><li><p><code>newEndIndex</code>：新列表结束索引</p></li></ul><h4 id="匹配顺序" tabindex="-1">匹配顺序 <a class="header-anchor" href="#匹配顺序" aria-label="Permalink to &quot;匹配顺序&quot;">​</a></h4><ol><li><p>头头匹配：旧列表起始节点 ↔ 新列表起始节点</p></li><li><p>尾尾匹配：旧列表结束节点 ↔ 新列表结束节点</p></li><li><p>旧头新尾匹配：旧列表起始节点 ↔ 新列表结束节点</p></li><li><p>旧尾新头匹配：旧列表结束节点 ↔ 新列表起始节点</p></li></ol><p>若以上四种匹配均失败，则遍历旧列表，根据 <code>key</code> 查找可复用节点。</p><h4 id="算法缺点" tabindex="-1">算法缺点 <a class="header-anchor" href="#算法缺点" aria-label="Permalink to &quot;算法缺点&quot;">​</a></h4><ul><li><p>属于启发式算法，DOM 移动次数不一定是最优解。</p></li><li><p>最坏时间复杂度接近 O(n²)（当列表完全逆序时）。</p></li><li><p>无法精准定位最少移动次数，性能上限较低。</p></li></ul><h3 id="_3-2-vue3-快速前后比对-lis-算法" tabindex="-1">3.2 Vue3：快速前后比对 + LIS 算法 <a class="header-anchor" href="#_3-2-vue3-快速前后比对-lis-算法" aria-label="Permalink to &quot;3\\.2 Vue3：快速前后比对 \\+ LIS 算法&quot;">​</a></h3><p>核心逻辑：先通过前后预处理快速缩小对比范围，再对中间乱序部分用 LIS 算法，实现 DOM 移动次数最少（最优解）。</p><h4 id="核心步骤" tabindex="-1">核心步骤 <a class="header-anchor" href="#核心步骤" aria-label="Permalink to &quot;核心步骤&quot;">​</a></h4><ol><li><p>前后预处理：从头、从尾同步比对新旧列表，跳过内容相同的节点，快速缩小中间乱序片段的范围。</p></li><li><p>乱序片段处理：对中间乱序的节点，建立 <code>key → 新列表索引</code> 的映射关系。</p></li><li><p>LIS 计算：找出乱序片段中「不需要移动的最长递增子序列」，该序列的节点可直接复用，无需移动。</p></li><li><p>节点移动：仅对最长递增子序列外的节点进行移动，确保 DOM 操作次数最少。</p></li></ol><h4 id="算法复杂度" tabindex="-1">算法复杂度 <a class="header-anchor" href="#算法复杂度" aria-label="Permalink to &quot;算法复杂度&quot;">​</a></h4><ul><li><p>前后预处理：O(n)（线性遍历）</p></li><li><p>LIS 计算：O(n log n)（最优时间复杂度）</p></li><li><p>整体效率远高于 Vue2 的双端对比算法，尤其适合长列表场景。</p></li></ul><h2 id="四、vue3-独有的编译期-diff-优化-核心亮点" tabindex="-1">四、Vue3 独有的编译期 Diff 优化（核心亮点） <a class="header-anchor" href="#四、vue3-独有的编译期-diff-优化-核心亮点" aria-label="Permalink to &quot;四、Vue3 独有的编译期 Diff 优化（核心亮点）&quot;">​</a></h2><p>Vue3 之所以 Diff 性能优于 Vue2，核心在于新增了<strong>编译期优化</strong>，提前标记动态节点，避免无效对比。</p><h3 id="_4-1-patchflag-靶向更新" tabindex="-1">4.1 PatchFlag（靶向更新） <a class="header-anchor" href="#_4-1-patchflag-靶向更新" aria-label="Permalink to &quot;4\\.1 PatchFlag（靶向更新）&quot;">​</a></h3><p>编译时给动态节点打上「更新类型标记」，运行时仅对比标记对应的内容，跳过无关属性/节点，实现精准更新。</p><p>常用 PatchFlag 类型：</p><ul><li><p><code>TEXT</code>：仅文本内容变化（如 <code>\\{\\{ msg \\}\\}</code>）。</p></li><li><p><code>CLASS</code>：仅 class 绑定变化（如 <code>:class=\\&amp;\\#34;activeClass\\&amp;\\#34;</code>）。</p></li><li><p><code>STYLE</code>：仅 style 绑定变化（如<code>:style=\\&amp;\\#34;\\{ color: red \\}\\&amp;\\#34;</code>）。</p></li><li><p><code>PROPS</code>：指定属性变化（如 <code>:id=\\&amp;\\#34;item\\.id\\&amp;\\#34;</code>）。</p></li><li><p><code>FULL\\_PROPS</code>：全量属性对比（无明确指定动态属性时）。</p></li></ul><h3 id="_4-2-静态提升-static-hoisting" tabindex="-1">4.2 静态提升（Static Hoisting） <a class="header-anchor" href="#_4-2-静态提升-static-hoisting" aria-label="Permalink to &quot;4\\.2 静态提升（Static Hoisting）&quot;">​</a></h3><p>纯静态节点（无任何动态绑定、无事件、无插槽）会被提升到渲染函数之外，<strong>只创建一次</strong>，后续组件更新时，直接跳过该节点的 Diff 对比，大幅减少冗余操作。</p><h3 id="_4-3-block-tree-块树优化" tabindex="-1">4.3 Block Tree（块树优化） <a class="header-anchor" href="#_4-3-block-tree-块树优化" aria-label="Permalink to &quot;4\\.3 Block Tree（块树优化）&quot;">​</a></h3><p>编译时将页面中的动态节点收集到「Block 块」中，形成 Block Tree。更新时，仅遍历 Block 块内的动态节点，不再递归整棵虚拟 DOM 树，减少遍历范围。</p><h3 id="_4-4-事件缓存" tabindex="-1">4.4 事件缓存 <a class="header-anchor" href="#_4-4-事件缓存" aria-label="Permalink to &quot;4\\.4 事件缓存&quot;">​</a></h3><p>内联事件函数（如 <code>@click=\\&amp;\\#34;handleClick\\&amp;\\#34;</code>）会被缓存，避免每次组件渲染时重新生成函数，减少不必要的 Diff 对比和函数创建开销。</p><h2 id="五、面试高频对比表-清晰易记" tabindex="-1">五、面试高频对比表（清晰易记） <a class="header-anchor" href="#五、面试高频对比表-清晰易记" aria-label="Permalink to &quot;五、面试高频对比表（清晰易记）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>对比维度</th><th>Vue2</th><th>Vue3</th></tr></thead><tbody><tr><td>核心 Diff 算法</td><td>双端双指针对比（启发式）</td><td>前后预处理 + 最长递增子序列（LIS）</td></tr><tr><td>对比范围</td><td>整棵虚拟 DOM 全量对比</td><td>仅对比带 PatchFlag 的动态节点</td></tr><tr><td>静态节点处理</td><td>每次更新都参与 Diff 对比</td><td>静态提升，完全跳过 Diff</td></tr><tr><td>列表移动优化</td><td>启发式，移动次数非最优</td><td>LIS 最优解，DOM 移动最少</td></tr><tr><td>编译期优化</td><td>无任何编译期优化</td><td>PatchFlag、静态提升、Block Tree、事件缓存</td></tr><tr><td>更新粒度</td><td>组件级更新为主</td><td>元素级、属性级精准更新</td></tr><tr><td>时间复杂度</td><td>近似 O(n)，最坏 O(n²)</td><td>O(n log n)（LIS 主导）</td></tr></tbody></table><h2 id="六、面试标准回答-可直接背诵" tabindex="-1">六、面试标准回答（可直接背诵） <a class="header-anchor" href="#六、面试标准回答-可直接背诵" aria-label="Permalink to &quot;六、面试标准回答（可直接背诵）&quot;">​</a></h2><p>Vue2 和 Vue3 的 Diff 算法核心区别主要有三点，精准对应考点，简洁不冗余：</p><ol><li><p>算法不同：Vue2 采用双端双指针对比（启发式），Vue3 采用前后预处理 + 最长递增子序列（LIS），实现最少 DOM 移动。</p></li><li><p>优化时机不同：Vue2 只有运行时优化，无编译期操作；Vue3 新增编译期优化（PatchFlag、静态提升等），提前标记动态节点。</p></li><li><p>对比范围不同：Vue2 全量遍历整棵虚拟 DOM，Vue3 只对比带标记的动态节点，性能大幅提升。</p></li></ol><h2 id="七、实际开发注意事项-延伸考点" tabindex="-1">七、实际开发注意事项（延伸考点） <a class="header-anchor" href="#七、实际开发注意事项-延伸考点" aria-label="Permalink to &quot;七、实际开发注意事项（延伸考点）&quot;">​</a></h2><ul><li><p>列表渲染必须使用<strong>稳定、唯一的 key</strong>，避免使用 index 作为 key，否则会导致 Diff 优化失效，甚至出现 DOM 渲染异常。</p></li><li><p>Vue3 中，大块静态内容（如固定文本、无动态绑定的布局）会被自动静态提升，无需手动优化。</p></li><li><p>Vue3 动态绑定越具体（如明确绑定单个属性），PatchFlag 标记越精准，Diff 效率越高。</p></li></ul><h2 id="补充说明" tabindex="-1">补充说明 <a class="header-anchor" href="#补充说明" aria-label="Permalink to &quot;补充说明&quot;">​</a></h2><p>本文档已完全适配 VitePress 渲染规则：标题层级规范（二级标题、三级标题、四级标题），确保侧边栏锚点正常生成；代码块指定语言，实现语法高亮；关键考点用加粗、代码块突出，提升可读性。直接复制到 VitePress 项目的 <code>\\.md</code> 文件中即可使用。</p><blockquote><p>（注：文档部分内容可能由 AI 生成）</p></blockquote>',47)])])}const f=a(o,[["render",d]]);export{s as __pageData,f as default};
